#!/usr/bin/env python3
import sys
import os
import datetime

class LogLevel:
    DEBUG = 10
    INFO = 20
    WARNING = 30
    ERROR = 40

    level_names = {
        DEBUG: "DEBUG",
        INFO: "INFO",
        WARNING: "WARNING",
        ERROR: "ERROR",
    }

    @classmethod
    def get_level_name(cls, level):
        return cls.level_names.get(level, "UNKNOWN")

class Formatter:
    def __init__(self, fmt="%(asctime)s - %(levelname)s - %(message)s", datefmt="%Y-%m-%d %H:%M:%S"):
        self.fmt = fmt
        self.datefmt = datefmt

    def format(self, level, message):
        record = {
            "asctime": datetime.datetime.now().strftime(self.datefmt),
            "levelname": LogLevel.get_level_name(level),
            "message": message,
        }
        return self.fmt % record

class BaseHandler:
    def __init__(self, formatter=None):
        self.formatter = formatter or Formatter()

    def emit(self, level, message):
        raise NotImplementedError("emit must be implemented by subclasses")

class ConsoleHandler(BaseHandler):
    def __init__(self, stream=sys.stdout, formatter=None):
        super().__init__(formatter)
        self.stream = stream

    def emit(self, level, message):
        formatted_message = self.formatter.format(level, message)
        print(formatted_message, file=self.stream)

class FileHandler(BaseHandler):
    def __init__(self, filename, mode="a", formatter=None):
        super().__init__(formatter)
        self.filename = filename
        self.mode = mode
        # Make sure file exists or is created
        self._ensure_file()

    def _ensure_file(self):
        # Create file if not exists
        if not os.path.exists(self.filename):
            with open(self.filename, "w"):
                pass

    def emit(self, level, message):
        formatted_message = self.formatter.format(level, message)
        with open(self.filename, self.mode, encoding="utf-8") as f:
            f.write(formatted_message + "\n")

class Logger:
    def __init__(self, level=LogLevel.DEBUG):
        self.level = level
        self.handlers = []

    def add_handler(self, handler):
        self.handlers.append(handler)

    def log(self, level, message):
        if level < self.level:
            return
        for handler in self.handlers:
            handler.emit(level, message)

    def debug(self, message):
        self.log(LogLevel.DEBUG, message)

    def info(self, message):
        self.log(LogLevel.INFO, message)

    def warning(self, message):
        self.log(LogLevel.WARNING, message)

    def error(self, message):
        self.log(LogLevel.ERROR, message)

# Example usage:
if __name__ == "__main__":
    # Create a logger with log level set to DEBUG
    logger = Logger(level=LogLevel.DEBUG)

    # Setup default formatter
    default_formatter = Formatter(fmt="%(asctime)s - %(levelname)s - %(message)s", datefmt="%Y-%m-%d %H:%M:%S")

    # Add console handler to logger
    console_handler = ConsoleHandler(formatter=default_formatter)
    logger.add_handler(console_handler)

    # Add file handler to logger (logs will be written to "app.log")
    file_handler = FileHandler("app.log", formatter=default_formatter)
    logger.add_handler(file_handler)

    # Log messages at various levels
    logger.debug("This is a debug message.")
    logger.info("Execution is proceeding as expected.")
    logger.warning("This is a warning about potential issues.")
    logger.error("An error occurred during execution.")

#!/usr/bin/env python3
import sys
import threading
from datetime import datetime

class LogLevel:
    DEBUG = 10
    INFO = 20
    WARNING = 30
    ERROR = 40
    CRITICAL = 50

    level_names = {
        DEBUG: 'DEBUG',
        INFO: 'INFO',
        WARNING: 'WARNING',
        ERROR: 'ERROR',
        CRITICAL: 'CRITICAL'
    }

    @classmethod
    def name(cls, level):
        return cls.level_names.get(level, 'LEVEL_%s' % level)

class Formatter:
    def __init__(self, fmt=None, datefmt=None):
        # Default format: [timestamp] [LEVEL] message
        self.fmt = fmt or "[{asctime}] [{level}] {message}"
        # Default date format: YYYY-mm-dd HH:MM:SS
        self.datefmt = datefmt or "%Y-%m-%d %H:%M:%S"

    def format(self, level, message):
        record = {
            'asctime': datetime.now().strftime(self.datefmt),
            'level': LogLevel.name(level),
            'message': message
        }
        return self.fmt.format(**record)

class Logger:
    def __init__(self, level=LogLevel.INFO, formatter=None, logfile=None):
        self.level = level
        self.formatter = formatter or Formatter()
        self.logfile = logfile
        # Protect file writes across threads
        self.lock = threading.Lock()
        if self.logfile:
            # Open file in append mode
            self.file_handler = open(self.logfile, "a")
        else:
            self.file_handler = None

    def _log(self, level, message):
        if level < self.level:
            return

        formatted_message = self.formatter.format(level, message)
        with self.lock:
            # Write to console
            print(formatted_message)
            sys.stdout.flush()
            # Write to file if available
            if self.file_handler:
                self.file_handler.write(formatted_message + "\n")
                self.file_handler.flush()

    def debug(self, message):
        self._log(LogLevel.DEBUG, message)

    def info(self, message):
        self._log(LogLevel.INFO, message)

    def warning(self, message):
        self._log(LogLevel.WARNING, message)

    def error(self, message):
        self._log(LogLevel.ERROR, message)

    def critical(self, message):
        self._log(LogLevel.CRITICAL, message)

    def setLevel(self, level):
        self.level = level

    def setFormatter(self, formatter):
        self.formatter = formatter

    def setLogfile(self, logfile):
        with self.lock:
            # Close old file if opened
            if self.file_handler:
                self.file_handler.close()
            self.logfile = logfile
            self.file_handler = open(self.logfile, 'a')

    def close(self):
        with self.lock:
            if self.file_handler:
                self.file_handler.close()
                self.file_handler = None

# Example usage:
if __name__ == "__main__":
    # Create logger with DEBUG level, custom format, and log file output.
    custom_format = "[{asctime}] | {level:<8} | {message}"
    formatter = Formatter(fmt=custom_format)
    logger = Logger(level=LogLevel.DEBUG, formatter=formatter, logfile="app.log")

    logger.debug("This is a debug message.")
    logger.info("This is an informational message.")
    logger.warning("This is a warning.")
    logger.error("An error has occurred!")
    logger.critical("Critical error! Shutting down.")

    # Change log level at runtime
    logger.setLevel(LogLevel.ERROR)
    logger.info("This info message will not appear because current level is ERROR.")
    logger.error("This error message will appear.")

    # Close the logger's file handle properly.
    logger.close()

