import datetime

class LogLevel:
    DEBUG = 10
    INFO = 20
    WARNING = 30
    ERROR = 40
    CRITICAL = 50

class Logger:
    def __init__(self, name="Logger", level=LogLevel.DEBUG, to_console=True, logfile=None):
        self.name = name
        self.level = level
        self.to_console = to_console
        self.logfile = logfile
        self.file_handle = None
        if self.logfile:
            self.file_handle = open(self.logfile, "a", encoding="utf-8")

    def _format_message(self, level_name, message):
        timestamp = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        return f"{timestamp} - {self.name} - {level_name} - {message}"

    def log(self, level, message):
        if level < self.level:
            return

        level_names = {
            LogLevel.DEBUG: "DEBUG",
            LogLevel.INFO: "INFO",
            LogLevel.WARNING: "WARNING",
            LogLevel.ERROR: "ERROR",
            LogLevel.CRITICAL: "CRITICAL"
        }
        level_name = level_names.get(level, "INFO")
        formatted = self._format_message(level_name, message)

        if self.to_console:
            print(formatted)
        if self.file_handle:
            self.file_handle.write(formatted + "\n")
            self.file_handle.flush()

    def debug(self, message):
        self.log(LogLevel.DEBUG, message)

    def info(self, message):
        self.log(LogLevel.INFO, message)

    def warning(self, message):
        self.log(LogLevel.WARNING, message)

    def error(self, message):
        self.log(LogLevel.ERROR, message)

    def critical(self, message):
        self.log(LogLevel.CRITICAL, message)

    def set_level(self, level):
        self.level = level

    def close(self):
        if self.file_handle:
            self.file_handle.close()
            self.file_handle = None

if __name__ == "__main__":
    # Example usage of Logger
    logger = Logger(name="MyAppLogger", level=LogLevel.DEBUG, to_console=True, logfile="application.log")
    logger.debug("Debug message: Starting the application.")
    logger.info("Info message: Application is running.")
    logger.warning("Warning message: Low disk space.")
    logger.error("Error message: Failed to load configuration.")
    logger.critical("Critical message: System shutdown imminent!")
    logger.close()

