#!/usr/bin/env python3
import sys
import os
import datetime

# Define numerical values for log levels for easy comparison
LOG_LEVELS = {
    "DEBUG": 10,
    "INFO": 20,
    "WARNING": 30,
    "ERROR": 40,
}


class Logger:
    def __init__(self, level="DEBUG", log_to_console=True, log_to_file=False, file_path="app.log"):
        """
        Initializes the Logger.

        Parameters:
            level (str): Minimum log level to log (DEBUG, INFO, WARNING, ERROR).
            log_to_console (bool): Whether to output logs to the console.
            log_to_file (bool): Whether to output logs to a file.
            file_path (str): Path to the log file.
        """
        self.level = level.upper()
        if self.level not in LOG_LEVELS:
            raise ValueError(f"Invalid log level: {level}")

        self.log_to_console = log_to_console
        self.log_to_file = log_to_file
        self.file_path = file_path

        self.file_handle = None
        if self.log_to_file:
            # Ensure the directory exists if file_path includes directories
            os.makedirs(os.path.dirname(os.path.abspath(self.file_path)), exist_ok=True)
            self.file_handle = open(self.file_path, "a")

    def _should_log(self, msg_level):
        return LOG_LEVELS[msg_level] >= LOG_LEVELS[self.level]

    def _format_message(self, level, message):
        # Format: YYYY-MM-DD HH:MM:SS [LEVEL] message
        now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        return f"{now} [{level}] {message}"

    def _log(self, level, message):
        if not self._should_log(level):
            return
        formatted_message = self._format_message(level, message)
        if self.log_to_console:
            print(formatted_message, file=sys.stdout)
        if self.log_to_file and self.file_handle:
            self.file_handle.write(formatted_message + "\n")
            self.file_handle.flush()

    def debug(self, message):
        self._log("DEBUG", message)

    def info(self, message):
        self._log("INFO", message)

    def warning(self, message):
        self._log("WARNING", message)

    def error(self, message):
        self._log("ERROR", message)

    def close(self):
        if self.file_handle:
            self.file_handle.close()
            self.file_handle = None

    def __del__(self):
        self.close()


if __name__ == "__main__":
    # Example usage:
    logger = Logger(level="DEBUG", log_to_console=True, log_to_file=True, file_path="app.log")

    logger.debug("This is a debug message.")
    logger.info("This is an info message.")
    logger.warning("This is a warning message.")
    logger.error("This is an error message.")

    logger.close()
